import { invokeFunction } from '../utils/zcutils';

export function executeMarkOperators(data, mapping, operators, customOperators) {
    let _this = this,
        _marks = new Array(0);
    operators.map(d => {
        let _thisTrack = mapping[d];
        if (_thisTrack) {
            let condition = _thisTrack.condition ? _thisTrack.condition.call(_this) : true,
                customOperator = customOperators && customOperators[d],
                mark,
                holder = _thisTrack.holder ? _thisTrack.holder.call(_this) : null;
            if (customOperator && customOperator.parser) {
                mark = invokeFunction(customOperator.parser, this, data, 'render', condition);
            } else {
                mark = _thisTrack.operator.call(this, data, 'render', condition);
            }

            if (customOperator && customOperator.extender) {
                mark = invokeFunction(customOperator.extender, this, mark);
            }
            _marks.push({
                mark,
                holder
            });
        } else {
            throw 'Mark operator is not defined';
        }
    });
    return _marks;
}
